export type Config = {
  /**
   * JSON schema reference for configuration validation
   */
  $schema?: string
  /**
   * Theme name to use for the interface
   */
  theme?: string
  keybinds?: KeybindsConfig
  logLevel?: LogLevel
  server?: ServerConfig
  /**
   * Command configuration
   */
  command?: {
    [key: string]: {
      template: string
      description?: string
      agent?: string
      model?: string
    }
  }
  watcher?: {
    ignore?: Array<string>
  }
  plugin?: Array<string>
  snapshot?: boolean
  /**
   * Automatically update to the latest version. Set to true to auto-update, false to disable, or 'notify' to show update notifications
   */
  autoupdate?: boolean | "notify"
  /**
   * Disable providers that are loaded automatically
   */
  disabled_providers?: Array<string>
  /**
   * When set, ONLY these providers will be enabled. All other providers will be ignored
   */
  enabled_providers?: Array<string>
  /**
   * Default model in the format of provider/model, eg anthropic/claude-sonnet-4-5
   */
  model?: string
  /**
   * Cheapest model for trivial extraction tasks like title generation, in the format of provider/model. Falls back to mini_model → mid_model → model.
   */
  nano_model?: string
  /**
   * Lightweight model for simple tasks like intent extraction, in the format of provider/model. Falls back to mid_model → model.
   */
  mini_model?: string
  /**
   * Mid-tier model for internal agents that need moderate reasoning (script extraction, reward evaluation, code exploration), in the format of provider/model. Falls back to the default model.
   */
  mid_model?: string
  /**
   * Deep thinking model for complex reasoning and architecture tasks, in the format of provider/model. Falls back to the default model if not set.
   */
  thinking_model?: string
  /**
   * Model with extra-large context window for processing very long inputs, in the format of provider/model. Falls back to the default model if not set.
   */
  long_context_model?: string
  /**
   * Model for creative and visual tasks (UI design, writing, artistry), in the format of provider/model. Falls back to the default model if not set.
   */
  creative_model?: string
  /**
   * Model for Holos automatic friend replies, in the format of provider/model. Falls back to the default model if not set.
   */
  holos_friend_reply_model?: string
  /**
   * Model for vision tasks (image/PDF/video analysis), in the format of provider/model. Required for the look_at tool to work. If not set, vision capabilities are disabled.
   */
  vision_model?: string
  /**
   * Default agent to use when none is specified. Must be a primary agent. Falls back to 'synergy' if not set or if the specified agent is invalid.
   */
  default_agent?: string
  /**
   * Custom username to display in conversations instead of system username
   */
  username?: string
  /**
   * Agent configuration
   */
  agent?: {
    master?: AgentConfig
    general?: AgentConfig
    explore?: AgentConfig
    title?: AgentConfig
    summary?: AgentConfig
    compaction?: AgentConfig
    [key: string]: AgentConfig | undefined
  }
  /**
   * External agent configurations (e.g. codex, claude-code)
   */
  external_agent?: {
    [key: string]: ExternalAgentConfig
  }
  /**
   * Custom provider configurations and model overrides
   */
  provider?: {
    [key: string]: ProviderConfig
  }
  identity?: IdentityConfig
  /**
   * MCP (Model Context Protocol) server configurations
   */
  mcp?: {
    [key: string]:
      | McpLocalConfig
      | McpRemoteConfig
      | {
          enabled: boolean
        }
  }
  /**
   * Channel configurations for messaging platform integrations
   */
  channel?: {
    [key: string]: ChannelFeishuConfig
  }
  holos?: HolosConfig
  email?: EmailConfig
  formatter?:
    | false
    | {
        [key: string]: {
          disabled?: boolean
          command?: Array<string>
          environment?: {
            [key: string]: string
          }
          extensions?: Array<string>
        }
      }
  lsp?:
    | false
    | {
        [key: string]:
          | {
              disabled: true
            }
          | {
              command: Array<string>
              extensions?: Array<string>
              disabled?: boolean
              env?: {
                [key: string]: string
              }
              initialization?: {
                [key: string]: unknown
              }
            }
      }
  /**
   * Additional instruction files or patterns to include
   */
  instructions?: Array<string>
  layout?: LayoutConfig
  permission?: PermissionConfig
  tools?: {
    [key: string]: boolean
  }
  enterprise?: {
    /**
     * Enterprise URL
     */
    url?: string
  }
  /**
   * Agora Q&A platform configuration
   */
  agora?: {
    /**
     * Agora API base URL (defaults to https://agora.holosai.io)
     */
    url?: string
    /**
     * Holos API URL for Agora token exchange (defaults to https://www.holosai.io)
     */
    tokenUrl?: string
    /**
     * Override SSH hostname used for Agora's Gitea remote
     */
    giteaSSHHost?: string
  }
  question?: {
    /**
     * Seconds before unanswered questions auto-expire (0 = no timeout, default 1800 = 30min)
     */
    timeout?: number
  }
  compaction?: {
    /**
     * Enable automatic compaction when context is full (default: true)
     */
    auto?: boolean
    /**
     * Enable pruning of old tool outputs (default: true)
     */
    prune?: boolean
    /**
     * Fraction of usable context that triggers auto-compaction (default: 0.85)
     */
    overflowThreshold?: number
  }
  experimental?: {
    /**
     * Enable the batch tool
     */
    batch_tool?: boolean
    /**
     * Enable OpenTelemetry spans for AI SDK calls (using the 'experimental_telemetry' flag)
     */
    openTelemetry?: boolean
    /**
     * Tools that should only be available to primary agents.
     */
    primary_tools?: Array<string>
    /**
     * Continue the agent loop when a tool call is denied
     */
    continue_loop_on_deny?: boolean
    /**
     * Timeout in milliseconds for model context protocol (MCP) requests
     */
    mcp_timeout?: number
  }
  /**
   * Custom category configurations for background tasks. Categories define model and prompt presets.
   */
  category?: {
    [key: string]: CategoryConfig
  }
}

